def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    pts = np.asarray(points, dtype=float)
    if pts.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N, D = pts.shape

    if k <= 0:
        return np.empty((0, D), dtype=pts.dtype)
    if N == 0:
        return np.empty((0, D), dtype=pts.dtype)
    if k >= N:
        return pts.copy()

    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # Fast axis-aligned box volume proxy (cheap)
    delta = np.clip(reference_point - pts, a_min=0.0, a_max=None)
    with np.errstate(invalid='ignore'):
        box_vol = np.prod(delta, axis=1)
    box_vol = np.clip(box_vol, a_min=0.0, a_max=None)

    # build initial candidate pool by top box_vol with skyline pruning
    initial_cap = int(min(N, max(6 * k, 200)))
    order = np.argsort(-box_vol, kind='mergesort')
    initial_candidates = order[:initial_cap].tolist()

    def nondominated_subset(indices):
        kept = []
        for idx in indices:
            p = pts[idx]
            dominated = False
            for j in kept:
                q = pts[j]
                if np.all(q <= p) and np.any(q < p):
                    dominated = True
                    break
            if dominated:
                continue
            to_remove = []
            for j in kept:
                q = pts[j]
                if np.all(p <= q) and np.any(p < q):
                    to_remove.append(j)
            for tr in to_remove:
                kept.remove(tr)
            kept.append(idx)
        return kept

    nd = nondominated_subset(initial_candidates)
    if len(nd) >= k:
        candidates = nd[:initial_cap]
    else:
        candidates = initial_candidates

    # Try to import pygmo for exact hypervolume computations
    try:
        import pygmo as pg
        HAVE_PG = True
    except Exception:
        HAVE_PG = False

    # If no pygmo, fallback to very fast proxy selection (box_vol among candidates)
    if not HAVE_PG:
        # choose top-k by box_vol (within candidates)
        cand_arr = np.array(candidates, dtype=int)
        if cand_arr.size == 0:
            # fallback to global top-k
            idxs = np.argsort(-box_vol)[:k]
            return pts[idxs].copy()
        sub_order = np.argsort(-box_vol[cand_arr])[:k]
        pick = cand_arr[sub_order]
        if pick.size < k:
            # pad from global order
            remaining = [i for i in order if i not in set(pick)]
            add = remaining[:(k - pick.size)]
            pick = np.concatenate([pick, np.array(add, dtype=int)])
        return pts[np.array(pick[:k], dtype=int)].copy()

    # If pygmo available, use reduced-pool CELF-like batched greedy with hv caching
    hv_cache = {}

    def compute_hv_by_indices(idxs):
        # idxs: iterable of global indices
        key = tuple(sorted(int(i) for i in idxs))
        if not key:
            return 0.0
        if key in hv_cache:
            return hv_cache[key]
        arr = pts[np.array(key, dtype=int), :]
        hv = pg.hypervolume(arr)
        val = float(hv.compute(reference_point))
        hv_cache[key] = val
        return val

    # Precompute single-point hv for candidates (cheap relative to multi-point)
    single_hv = {}
    for idx in candidates:
        single_hv[idx] = compute_hv_by_indices([idx])

    # Build initial heap on candidate pool with cached single-point marginals
    heap = []
    for idx in candidates:
        gain = float(max(0.0, single_hv.get(idx, 0.0)))
        heap.append((-gain, int(idx)))
    heapq.heapify(heap)

    selected_list = []
    selected_set = set()
    current_selected = []  # store global indices
    current_hv = 0.0

    # Batch size B: number of popped candidates evaluated exactly per selection
    # Keep B small to reduce number of exact HV evaluations
    B = min(12, max(3, int(max(1, len(candidates) // max(1, (k + 1))))))
    # Ensure B at least 3 and not too big
    B = int(B)

    # Main loop: in each iteration pop up to B top candidates, compute true marginals, pick best
    while len(selected_list) < k and heap:
        batch = []
        popped = []
        while len(batch) < B and heap:
            neg_gain, idx = heapq.heappop(heap)
            if int(idx) in selected_set:
                continue
            batch.append(int(idx))
            popped.append((neg_gain, int(idx)))
        if not batch:
            break

        best_idx = None
        best_gain = -np.inf
        best_hv_with = None

        # Evaluate exact marginal hv for each in batch
        for idx in batch:
            if not current_selected:
                hv_with = single_hv.get(idx, compute_hv_by_indices([idx]))
            else:
                hv_with = compute_hv_by_indices(current_selected + [idx])
            marginal = hv_with - current_hv
            if marginal > best_gain:
                best_gain = marginal
                best_idx = idx
                best_hv_with = hv_with

        # Push back other batch members with updated cached marginal estimates
        for idx in batch:
            if idx == best_idx:
                continue
            if not current_selected:
                hv_with = single_hv.get(idx, compute_hv_by_indices([idx]))
            else:
                hv_with = compute_hv_by_indices(current_selected + [idx])
            marginal = float(max(0.0, hv_with - current_hv))
            heapq.heappush(heap, (-marginal, int(idx)))

        # Accept the best (even if non-positive to fill quota)
        if best_idx is None:
            break
        selected_list.append(int(best_idx))
        selected_set.add(int(best_idx))
        current_selected.append(int(best_idx))
        current_hv = float(best_hv_with)

    # If still short, fill from remaining candidates by box_vol ranking
    if len(selected_list) < k:
        rem = [i for i in candidates if i not in selected_set]
        rem_sorted = sorted(rem, key=lambda x: -box_vol[x])
        for idx in rem_sorted:
            if idx in selected_set:
                continue
            selected_list.append(int(idx))
            selected_set.add(int(idx))
            if len(selected_list) >= k:
                break

    # If still short, fill from global remaining by box_vol
    if len(selected_list) < k:
        rem_all = [i for i in order if i not in selected_set]
        for idx in rem_all:
            selected_list.append(int(idx))
            selected_set.add(int(idx))
            if len(selected_list) >= k:
                break

    # Final safety: if somehow still short, pad arbitrarily (should not happen)
    if len(selected_list) < k:
        for i in range(N):
            if i not in selected_set:
                selected_list.append(int(i))
                selected_set.add(int(i))
                if len(selected_list) >= k:
                    break

    selected_indices = np.array(selected_list[:k], dtype=int)
    return pts[selected_indices, :].copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq

    pts = np.asarray(points, dtype=float)
    if pts.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N, D = pts.shape

    if k <= 0:
        return np.empty((0, D), dtype=pts.dtype)
    if N == 0:
        return np.empty((0, D), dtype=pts.dtype)
    if k >= N:
        return pts.copy()

    if reference_point is None:
        reference_point = np.max(pts, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # quick box volumes (proxy / cheap singleton HV)
    delta = np.clip(reference_point - pts, a_min=0.0, a_max=None)
    with np.errstate(invalid='ignore'):
        box_vol = np.prod(delta, axis=1)
    box_vol = np.clip(box_vol, a_min=0.0, a_max=None)

    # fast nondominated extraction (minimization: smaller coordinates dominate)
    def nondominated_indices(idx_list):
        arr = pts[np.array(idx_list, dtype=int), :]
        order = np.argsort(np.sum(arr, axis=1), kind='mergesort')
        ordered = [idx_list[i] for i in order]
        kept = []
        for idx in ordered:
            p = pts[idx]
            dominated = False
            for j in kept:
                q = pts[j]
                if np.all(q <= p) and np.any(q < p):
                    dominated = True
                    break
            if not dominated:
                # remove those dominated by p
                to_remove = []
                for j in kept:
                    q = pts[j]
                    if np.all(p <= q) and np.any(p < q):
                        to_remove.append(j)
                for tr in to_remove:
                    kept.remove(tr)
                kept.append(idx)
        return kept

    # build compact candidate pool: prefer nondominated then top by box_vol
    all_idxs = list(range(N))
    nd = nondominated_indices(all_idxs)
    if len(nd) == 0:
        nd = all_idxs
    # choose cap size
    cap = int(min(len(nd), max(6 * k, 200)))
    if len(nd) <= cap:
        candidates = nd
    else:
        # rank nondominated by box_vol
        candidates = sorted(nd, key=lambda i: -box_vol[i])[:cap]

    # fallback ensure at least k candidates
    if len(candidates) < k:
        order_by_box = np.argsort(-box_vol, kind='mergesort')
        for i in order_by_box:
            if i not in candidates:
                candidates.append(int(i))
            if len(candidates) >= k:
                break

    # prepare hypervolume computation (exact if pygmo available, else MC approx)
    try:
        import pygmo as pg  # type: ignore
        _have_pygmo = True
    except Exception:
        _have_pygmo = False

    hv_cache = {}

    def approx_hv_mc(arr_pts: np.ndarray, ref: np.ndarray, samples: int = None) -> float:
        if arr_pts.size == 0:
            return 0.0
        Dloc = arr_pts.shape[1]
        if samples is None:
            samples = int(min(5000, max(1000, 500 * Dloc)))
        # domain: sample uniformly in box [mins, ref] where mins = minimum over arr_pts clipped below ref
        mins = np.min(arr_pts, axis=0)
        # if any mins >= ref, HV=0
        if np.any(mins >= ref):
            return 0.0
        rng = np.random.default_rng(12345)
        u = rng.random((samples, Dloc))
        samples_coords = mins + u * (ref - mins)
        dominated = np.zeros(samples, dtype=bool)
        # vectorized check by chunks to limit memory if many points
        for p in arr_pts:
            dominated |= np.all(p <= samples_coords, axis=1)
            if dominated.all():
                break
        frac = float(dominated.mean())
        volume_box = float(np.prod(ref - mins))
        return frac * volume_box

    def hv_of_points(arr_pts: np.ndarray) -> float:
        # arr_pts: (m, D)
        if arr_pts.size == 0:
            return 0.0
        key = None
        # try to form a hashable signature: use tuples of rounded values to avoid huge keys
        try:
            key = tuple(map(tuple, np.round(arr_pts.astype(float), decimals=8).tolist()))
        except Exception:
            key = None
        if key is not None and key in hv_cache:
            return hv_cache[key]
        if _have_pygmo:
            hv = pg.hypervolume(arr_pts)
            val = float(hv.compute(reference_point))
        else:
            val = float(approx_hv_mc(arr_pts, reference_point))
        if key is not None:
            hv_cache[key] = val
        return val

    # compute singletons for candidates (exact if pygmo, else box_vol proxy)
    single_hv = {}
    for idx in candidates:
        if box_vol[idx] <= 0:
            single_hv[idx] = 0.0
        else:
            if _have_pygmo:
                single_hv[idx] = hv_of_points(pts[[idx], :])
            else:
                single_hv[idx] = float(box_vol[idx])  # cheap proxy

    # initial heap entries: (-gain, idx, version)
    heap = []
    for idx in candidates:
        gain = max(0.0, float(single_hv.get(idx, 0.0)))
        heap.append((-gain, int(idx), 0))
    heapq.heapify(heap)

    selected = []
    selected_set = set()
    current_selected_points = np.empty((0, D), dtype=float)
    current_hv = 0.0
    selected_count = 0
    max_iters = len(candidates) * 2 + k * 5

    iters = 0
    while selected_count < k and heap and iters < max_iters:
        iters += 1
        neg_gain, idx, ver = heapq.heappop(heap)
        idx = int(idx)
